INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('drug_reference', 'doxycycline', ARRAY['دوكسيسايكلين','مضاد حيوي','تتراسيكلين','عدوى'], 'دوكسيسايكلين', E'## دوكسيسايكلين\n\n**التصنيف:** مضاد حيوي من مجموعة التتراسيكلين\n\n**الجرعة:** 100 ملغ مرتين يومياً\n\n**الاستخدامات:** التهابات الجهاز التنفسي، حب الشباب، الملاريا (وقائي)، الكلاميديا\n\n**الآثار الجانبية:** حساسية للشمس، غثيان، التهاب المريء\n\n**تحذيرات:**\n- ممنوع للحوامل والأطفال أقل من 8 سنوات\n- تناوله مع كمية كافية من الماء\n- تجنب منتجات الألبان ومضادات الحموضة', 'ar', 'BNF', 7, true),
('drug_reference', 'ranitidine', ARRAY['رانيتيدين','حموضة','قرحة','معدة'], 'رانيتيدين', E'## رانيتيدين\n\n**التصنيف:** مضاد لمستقبلات H2\n\n**الجرعة:** 150 ملغ مرتين يومياً أو 300 ملغ مرة واحدة ليلاً\n\n**الاستخدامات:** قرحة المعدة والاثني عشر، ارتجاع المريء\n\n**ملاحظة:** تم سحبه من بعض الأسواق بسبب مخاوف NDMA\n\n**البديل:** أوميبرازول 20 ملغ يومياً', 'ar', 'BNF', 7, true),
('drug_reference', 'loperamide', ARRAY['لوبيراميد','إسهال','إيموديوم'], 'لوبيراميد', E'## لوبيراميد\n\n**التصنيف:** مضاد للإسهال\n\n**الجرعة:** 4 ملغ جرعة أولى ثم 2 ملغ بعد كل إسهال (أقصى 16 ملغ/يوم)\n\n**الاستخدامات:** الإسهال الحاد غير المعدي\n\n**تحذيرات:**\n- لا يستخدم في الإسهال الدموي أو مع حمى\n- لا يستخدم للأطفال أقل من سنتين\n- يوقف إذا لم يتحسن خلال 48 ساعة', 'ar', 'BNF', 7, true),
('drug_reference', 'ors', ARRAY['محلول الجفاف','إسهال','جفاف','أملاح'], 'محلول الإماهة الفموية ORS', E'## محلول الإماهة الفموية\n\n**التركيبة:** صوديوم، بوتاسيوم، جلوكوز، سترات\n\n**التحضير:** كيس واحد في لتر ماء نظيف\n\n**الجرعة:**\n- أقل من سنتين: 50-100 مل بعد كل إسهال\n- 2-10 سنوات: 100-200 مل\n- أكبر من 10 سنوات: حسب الحاجة\n\n**علامات الجفاف الشديد:** عيون غائرة، جلد غير مرن، بول قليل → تحويل فوري للمستشفى', 'ar', 'WHO', 7, true);
INSERT INTO public.medical_knowledge (category, condition, keywords, title, content, language, source, priority, is_active) VALUES
('clinical_guideline', 'diabetes_type2', ARRAY['سكري','النوع الثاني','ميتفورمين','سكر الدم'], 'إدارة السكري النوع الثاني', E'## إدارة السكري النوع الثاني\n\n**التشخيص:** سكر صائم ≥126 أو HbA1c ≥6.5%\n\n**الخطوة 1:** تعديل نمط الحياة + ميتفورمين 500 ملغ مرتين\n**الخطوة 2:** إضافة سلفونيليوريا أو مثبط DPP-4\n**الخطوة 3:** إضافة إنسولين قاعدي\n\n**الأهداف:**\n- HbA1c < 7%\n- سكر صائم 80-130 ملغ/دل\n- ضغط الدم < 130/80\n\n**الفحوصات الدورية:** HbA1c كل 3 أشهر، فحص قدم سنوي، فحص عيون سنوي، وظائف كلى سنوياً', 'ar', 'ADA/WHO', 6, true),
('clinical_guideline', 'hypertension', ARRAY['ضغط الدم','ارتفاع الضغط','أملوديبين','لوسارتان'], 'علاج ارتفاع ضغط الدم', E'## علاج ارتفاع ضغط الدم التدريجي\n\n**التشخيص:** ≥140/90 في قياسين منفصلين\n\n**الخطوة 1:** مثبط ACE أو ARB (مع مدر بول لكبار السن)\n**الخطوة 2:** إضافة حاصرات قنوات الكالسيوم\n**الخطوة 3:** إضافة مدر بول ثيازيدي\n**الخطوة 4:** إضافة سبيرونولاكتون\n\n**الهدف:** < 140/90 (< 130/80 للسكري)\n\n**طوارئ:** ضغط > 180/120 مع أعراض → تحويل فوري', 'ar', 'NICE/JNC', 6, true),
('clinical_guideline', 'asthma_action', ARRAY['ربو','بخاخ','سالبوتامول','كورتيزون'], 'خطة إدارة الربو', E'## خطة إدارة الربو\n\n**الخطوة 1:** سالبوتامول عند الحاجة\n**الخطوة 2:** إضافة كورتيكوستيرويد استنشاقي جرعة منخفضة\n**الخطوة 3:** إضافة LABA أو زيادة جرعة ICS\n**الخطوة 4:** ICS جرعة متوسطة + LABA\n**الخطوة 5:** إحالة لأخصائي\n\n**النوبة الحادة:**\n- سالبوتامول 4-10 بخات كل 20 دقيقة\n- بريدنيزولون 40-50 ملغ لمدة 5 أيام\n- أكسجين للحفاظ على SpO2 > 94%\n\n**إحالة طارئة:** عدم تحسن، صعوبة الكلام، SpO2 < 92%', 'ar', 'BTS/GINA', 6, true),
('clinical_guideline', 'copd_management', ARRAY['انسداد رئوي','copd','ضيق تنفس','تدخين'], 'إدارة مرض الانسداد الرئوي المزمن', E'## إدارة COPD\n\n**التشخيص:** FEV1/FVC < 0.7 بعد موسع قصبي\n\n**العلاج التدريجي:**\n- المجموعة A: موسع قصبي قصير المفعول عند الحاجة\n- المجموعة B: LABA أو LAMA\n- المجموعة E: LABA + LAMA ± ICS\n\n**أساسيات:**\n- إيقاف التدخين (الأهم)\n- تطعيم الإنفلونزا والمكورات الرئوية\n- إعادة تأهيل رئوي\n\n**النوبة الحادة:** بريدنيزولون 30-40 ملغ × 5 أيام + مضاد حيوي إذا كان البلغم صديدياً', 'ar', 'GOLD/NICE', 6, true),
('clinical_guideline', 'pregnancy_care', ARRAY['حمل','رعاية حامل','حمض الفوليك','متابعة حمل'], 'رعاية الحمل الروتينية', E'## رعاية الحمل\n\n**الثلث الأول:**\n- حمض الفوليك 400 ميكروجرام يومياً\n- فحوصات: فصيلة الدم، CBC، سكر، بول، HIV، HBsAg\n- سونار تأكيدي الأسبوع 12\n\n**الثلث الثاني:**\n- حديد + فوليك يومياً\n- فحص التشوهات الأسبوع 20\n- فحص سكر الحمل الأسبوع 24-28\n\n**الثلث الثالث:**\n- متابعة ضغط الدم وزلال البول\n- فحص وضعية الجنين\n\n**علامات الخطر:** نزيف مهبلي، صداع شديد، تورم مفاجئ، قلة حركة الجنين', 'ar', 'WHO/NICE', 6, true),
('clinical_guideline', 'anemia_workup', ARRAY['فقر دم','أنيميا','هيموجلوبين','حديد'], 'فحص وعلاج فقر الدم', E'## فحص وعلاج فقر الدم\n\n**التشخيص:** Hb < 13 ذكور، < 12 إناث\n\n**الفحوصات:**\n1. CBC + فيلم دم\n2. حديد المصل، فيريتين، TIBC\n3. B12 وحمض الفوليك\n4. وظائف كلى وكبد\n\n**العلاج حسب النوع:**\n- نقص حديد: فيروس سلفات 200 ملغ × 3 يومياً لمدة 3 أشهر\n- نقص B12: حقن 1000 ميكروجرام\n- نقص فوليك: 5 ملغ يومياً\n\n**تحويل عاجل:** Hb < 7 أو نزيف نشط أو أعراض قلبية', 'ar', 'WHO/BSH', 6, true),
('clinical_guideline', 'thyroid_disorders', ARRAY['غدة درقية','ثايرويد','TSH','هرمونات'], 'اضطرابات الغدة الدرقية', E'## اضطرابات الغدة الدرقية\n\n**قصور الدرقية:**\n- الأعراض: تعب، زيادة وزن، إمساك، جفاف جلد\n- التشخيص: TSH مرتفع، T4 منخفض\n- العلاج: ليفوثيروكسين 25-50 ميكروجرام بدءاً\n\n**فرط الدرقية:**\n- الأعراض: خفقان، نقص وزن، رعشة، تعرق\n- التشخيص: TSH منخفض، T4/T3 مرتفع\n- العلاج: كاربيمازول + حاصر بيتا\n\n**متابعة:** TSH كل 6-8 أسابيع حتى الاستقرار ثم كل 6 أشهر', 'ar', 'ATA/NICE', 6, true),
('clinical_guideline', 'depression_screening', ARRAY['اكتئاب','PHQ-9','صحة نفسية','مزاج'], 'فحص وعلاج الاكتئاب', E'## فحص الاكتئاب (PHQ-9)\n\n**الدرجات:**\n- 5-9: خفيف → مراقبة\n- 10-14: متوسط → علاج نفسي ± دوائي\n- 15-19: شديد → SSRI + علاج نفسي\n- ≥20: شديد جداً → إحالة عاجلة\n\n**العلاج الدوائي:**\n- الخط الأول: فلوكسيتين 20 ملغ أو سيرترالين 50 ملغ\n- تقييم بعد 4-6 أسابيع\n- استمرار لمدة 6 أشهر بعد التحسن\n\n**⚠️ تحويل فوري:** أفكار انتحارية أو إيذاء النفس', 'ar', 'NICE/WHO', 6, true),
('clinical_guideline', 'pediatric_diarrhea', ARRAY['إسهال أطفال','جفاف','ORS','زنك'], 'إسهال الأطفال والجفاف', E'## إسهال الأطفال\n\n**تقييم الجفاف:**\n- لا جفاف: خطة أ - ORS بعد كل إسهال\n- جفاف متوسط: خطة ب - ORS 75 مل/كغ خلال 4 ساعات\n- جفاف شديد: خطة ج - سوائل وريدية فوراً\n\n**العلاج:**\n1. ORS حسب درجة الجفاف\n2. زنك 20 ملغ/يوم × 10-14 يوم (10 ملغ لأقل من 6 أشهر)\n3. استمرار الرضاعة والتغذية\n4. لا مضادات حيوية إلا في الدموي\n\n**تحويل فوري:** جفاف شديد، دم في البراز، حمى عالية مع عمر < 3 أشهر', 'ar', 'WHO/IMCI', 6, true),
('clinical_guideline', 'malaria_treatment', ARRAY['ملاريا','حمى','بلازموديوم','أرتيميسينين'], 'علاج الملاريا', E'## علاج الملاريا\n\n**التشخيص:** فحص شريحة دم أو RDT\n\n**P. falciparum (غير مقاوم):**\n- ACT: أرتيميثير-لوميفانترين × 3 أيام\n- أو أرتيسونيت + أموداياكين\n\n**P. vivax:**\n- كلوروكين × 3 أيام + بريماكين 14 يوم\n- فحص G6PD قبل بريماكين\n\n**الملاريا الشديدة:**\n- أرتيسونيت وريدي + تحويل للمستشفى\n\n**الوقاية:** ناموسيات معالجة، رش داخلي', 'ar', 'WHO', 6, true),
('clinical_guideline', 'tb_screening', ARRAY['سل','درن','tuberculosis','سعال مزمن'], 'فحص وعلاج السل', E'## فحص السل\n\n**الاشتباه:** سعال > أسبوعين، حمى ليلية، تعرق، نقص وزن\n\n**الفحوصات:**\n1. صورة صدر\n2. فحص بلغم × 3 (صبغة وزراعة)\n3. GeneXpert إن أمكن\n\n**العلاج:**\n- المرحلة المكثفة (شهران): HRZE\n- مرحلة الاستمرار (4 أشهر): HR\n- DOT (العلاج تحت المراقبة المباشرة)\n\n**متابعة:** فحص بلغم الشهر 2 و5 و6\n\n**تحويل:** مقاومة أدوية، سل خارج رئوي، فشل علاج', 'ar', 'WHO/NTCP', 6, true),
('clinical_guideline', 'hiv_pep', ARRAY['HIV','PEP','وقاية','إبرة ملوثة'], 'الوقاية بعد التعرض لـ HIV', E'## PEP - الوقاية بعد التعرض\n\n**البدء:** خلال 72 ساعة (الأفضل خلال ساعتين)\n\n**النظام:**\n- TDF + 3TC (أو FTC) + دولوتيجرافير\n- المدة: 28 يوم\n\n**الفحوصات:**\n- فحص HIV قبل البدء (يجب أن يكون سلبياً)\n- وظائف كلى وكبد\n- متابعة: فحص HIV بعد 6 أسابيع و3 أشهر و6 أشهر\n\n**حالات التعرض:** وخز إبرة، تعرض جنسي، تعرض لدم ملوث', 'ar', 'WHO', 6, true),
('clinical_guideline', 'wound_care', ARRAY['جرح','خياطة','تنظيف جرح','تيتانوس'], 'إدارة الجروح', E'## إدارة الجروح\n\n**التنظيف:**\n1. غسل بمحلول ملحي أو ماء نظيف\n2. إزالة الأجسام الغريبة\n3. تطهير بالبوفيدون أيودين\n\n**الخياطة:** خلال 6 ساعات (الوجه حتى 24 ساعة)\n\n**المضاد الحيوي:** للجروح الملوثة أو العضات\n- أموكسيسيلين/كلافيولانات 625 ملغ × 3\n\n**التيتانوس:**\n- جرح نظيف + تطعيم كامل: لا حاجة\n- جرح ملوث: جرعة منشطة + إيمينوجلوبولين إذا لم يكتمل التطعيم\n\n**متابعة:** فك الخيوط بعد 7-10 أيام (الوجه 5 أيام)', 'ar', 'WHO', 6, true),
('clinical_guideline', 'burns_management', ARRAY['حرق','حروق','درجة','مساحة'], 'إدارة الحروق', E'## إدارة الحروق\n\n**تصنيف الدرجات:**\n- الأولى: احمرار فقط\n- الثانية: فقاعات\n- الثالثة: بيضاء/متفحمة\n\n**الإسعاف الأولي:**\n1. تبريد بماء جارٍ 20 دقيقة\n2. إزالة المجوهرات والملابس غير الملتصقة\n3. تغطية بضماد نظيف\n\n**حساب المساحة:** قاعدة التسعات أو كف المريض = 1%\n\n**تحويل للمستشفى:**\n- مساحة > 10% بالغ أو > 5% طفل\n- حروق الوجه أو اليدين أو المنطقة التناسلية\n- حروق كهربائية أو كيميائية\n- حروق دائرية\n\n**السوائل:** فورمولا باركلاند: 4 مل × كغ × % مساحة', 'ar', 'WHO/ABA', 6, true),
('clinical_guideline', 'fracture_first_aid', ARRAY['كسر','جبيرة','عظم','إصابة'], 'الإسعاف الأولي للكسور', E'## الإسعاف الأولي للكسور\n\n**العلامات:** ألم شديد، تورم، تشوه، عدم القدرة على الحركة\n\n**الإسعاف:**\n1. تثبيت الطرف بجبيرة مؤقتة\n2. ثلج (20 دقيقة كل ساعة)\n3. رفع الطرف\n4. مسكن: باراسيتامول أو ترامادول\n\n**⚠️ كسر مفتوح:**\n- تغطية بضماد معقم\n- عدم محاولة إرجاع العظم\n- مضاد حيوي + تيتانوس\n- تحويل جراحي عاجل\n\n**تحويل فوري:** فقدان النبض، تنميل، كسر مفتوح، كسر الحوض أو الفخذ', 'ar', 'ATLS/WHO', 6, true);
